"""
generate_dashboard.py
----------------------
Regenerate the Retail Sales Performance Dashboard (HTML) -- Handset page,
Accessories page, AND Trend Performance page -- from an updated
Refresh_TSM.xlsx export, and (optionally) an updated shop master list.

USAGE:
    python generate_dashboard.py                                   (Refresh_TSM.xlsx in this folder, default 61-shop master list baked in)
    python generate_dashboard.py path/to/Refresh_TSM.xlsx
    python generate_dashboard.py path/to/Refresh_TSM.xlsx path/to/output.html
    python generate_dashboard.py path/to/Refresh_TSM.xlsx path/to/output.html path/to/List_XX_Shop.xlsx

Requirements:
    pip install pandas openpyxl

What it does:
    1. Reads the "TSM" sheet -- builds the Handset and Accessories pages
       (TYPE SHOP in Hall/COCO), each with independent filters (Region /
       Shop Type / Area multi-select / Date / Shop Name search), KPIs,
       Daily Trend, Regional Performance, Area Drill-down, Shop
       Leaderboard (all shops incl. zero-sale), Brand Market Share, and
       Top Models/Products charts.
    2. Reads the "MOM AMOUNT" sheet -- builds the Trend Performance page:
       a summary banner (previous/current month totals, overall MOM%,
       shop-count tiers: Negative / 0-30% / 30-50% / 50-100% / >100%,
       "Data as of" date) and an overall monthly trend line chart -- both
       recompute live from the table filters -- plus a scrollable /
       freeze-paned shop-level table. ALL five table filters (Region,
       Area, Shop Type, Shop Name, Tier MOM) are multi-select dropdowns
       (checkbox panels with Select all / Clear, a search box for Area /
       Shop Name) and are fully CROSS-FILTERING / faceted: picking a
       value in one dropdown narrows the option lists shown in every
       other dropdown to only what's actually reachable (e.g. picking an
       Area shows only the Shop Names that exist in that area). Includes
       an "Export CSV" button that downloads exactly the currently
       filtered + sorted rows. Automatically adapts to however many
       month columns exist in the sheet (no hardcoded month range).
    3. Reads the shop master list (SHOP CODE / SHOP NAME / TYPE SHOP /
       AREA / Size Shop / REGION) -- either the file you pass as the 3rd
       argument, or the master list baked into this script from the last
       time you supplied one. Used by the Handset/Accessories Shop
       Leaderboards so zero-sale shops are never hidden.
    4. All filters, KPIs, and charts recompute automatically in the
       browser -- no manual editing needed after this script runs.

NOTE: If you get a new/updated shop list in the future (store openings,
closures, etc.), just pass it as the 3rd argument once -- this script
will use it for that run. To make it the new permanent default, ask
Claude to regenerate this script with the updated list baked in.
"""
import sys
import json
import pandas as pd

TEMPLATE = '<!DOCTYPE html>\n<html lang="th">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Handset Sales Performance — TSM Dashboard</title>\n<link rel="preconnect" href="https://fonts.googleapis.com">\n<link href="https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=IBM+Plex+Mono:wght@500;600&display=swap" rel="stylesheet">\n<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>\n<style>\n__CSS__\n</style>\n</head>\n<body>\n__BODY__\n<script>\nconst HANDSET_DATA = __HANDSET_DATA__;\nconst ACCESSORIES_DATA = __ACCESSORIES_DATA__;\nconst SHOPS_MASTER = __SHOPS__;\nconst MOM_PAYLOAD = __MOM_PAYLOAD__;\n__JS__\n</script>\n</body>\n</html>\n'
CSS = ":root{\n  --bg:#F3F4F8;\n  --surface:#FFFFFF;\n  --ink:#0E1526;\n  --ink-soft:#4B5468;\n  --muted:#8890A0;\n  --navy:#101B3D;\n  --navy-2:#182752;\n  --line:#E4E7EF;\n  --accent:#E8483C;\n  --accent-soft:#FCE7E5;\n  --teal:#1E9E86;\n  --teal-soft:#DFF5EF;\n  --amber:#D98A2B;\n  --amber-soft:#FBEEDD;\n  --radius:14px;\n  --shadow:0 1px 2px rgba(16,27,61,0.04), 0 8px 24px -12px rgba(16,27,61,0.12);\n}\n*{box-sizing:border-box;}\nhtml,body{margin:0;padding:0;}\nbody{\n  background:var(--bg);\n  color:var(--ink);\n  font-family:'Inter',-apple-system,BlinkMacSystemFont,sans-serif;\n  -webkit-font-smoothing:antialiased;\n}\n.num{font-family:'IBM Plex Mono',monospace;font-variant-numeric:tabular-nums;}\n\n/* ===== Header ===== */\n.topbar{\n  background:linear-gradient(135deg,var(--navy) 0%, var(--navy-2) 100%);\n  color:#fff;\n  padding:26px 36px 22px;\n}\n.topbar-inner{max-width:1360px;margin:0 auto;display:flex;justify-content:space-between;align-items:flex-end;gap:24px;flex-wrap:wrap;}\n.brand-eyebrow{\n  font-family:'IBM Plex Mono',monospace;\n  font-size:11px;letter-spacing:.14em;text-transform:uppercase;\n  color:#F0A79E;margin:0 0 8px;\n}\n.brand-title{\n  font-family:'Space Grotesk',sans-serif;\n  font-size:30px;font-weight:700;margin:0;letter-spacing:-0.01em;\n}\n.brand-sub{color:#AEB6D6;font-size:13px;margin-top:6px;}\n\n/* ===== Layout ===== */\n.wrap{max-width:1360px;margin:0 auto;padding:24px 36px 60px;}\n\n/* ===== Filter bar ===== */\n.filterbar{\n  background:var(--surface);\n  border:1px solid var(--line);\n  border-radius:var(--radius);\n  box-shadow:var(--shadow);\n  padding:18px 22px;\n  position:relative;\n  z-index:5;\n  display:flex;\n  gap:28px;\n  flex-wrap:wrap;\n  align-items:flex-start;\n}\n.filter-group{display:flex;flex-direction:column;gap:8px;}\n.filter-label{\n  font-size:10.5px;font-weight:600;letter-spacing:.09em;text-transform:uppercase;\n  color:var(--muted);\n}\n.filter-label-hint{\n  font-size:10px; font-weight:500; letter-spacing:0; text-transform:none;\n  color:#B7BCC9; margin-left:2px;\n}\n.chip-row{display:flex;gap:7px;flex-wrap:wrap;max-width:640px;}\n#areaChips{max-width:900px;}\n.chip{\n  border:1px solid var(--line);\n  background:#fff;\n  color:var(--ink-soft);\n  font-size:12.5px;\n  font-weight:500;\n  padding:7px 13px;\n  border-radius:8px;\n  cursor:pointer;\n  transition:all .12s ease;\n  white-space:nowrap;\n}\n.chip:hover{border-color:var(--accent);color:var(--accent);}\n.chip.active{\n  background:var(--navy);\n  border-color:var(--navy);\n  color:#fff;\n}\n.chip.active.date{background:var(--teal);border-color:var(--teal);}\n.reset-btn{\n  margin-left:auto;\n  align-self:center;\n  background:none;\n  border:1px solid var(--line);\n  color:var(--ink-soft);\n  font-size:12.5px;font-weight:600;\n  padding:9px 16px;\n  border-radius:8px;\n  cursor:pointer;\n}\n.reset-btn:hover{border-color:var(--ink);color:var(--ink);}\n\n.export-btn{\n  background:var(--navy);\n  border:1px solid var(--navy);\n  color:#fff;\n  font-size:12.5px;font-weight:600;\n  padding:9px 16px;\n  border-radius:8px;\n  cursor:pointer;\n  white-space:nowrap;\n}\n.export-btn:hover{background:var(--navy-2);}\n\n.shop-search{\n  border:1px solid var(--line);\n  background:#fff;\n  color:var(--ink);\n  font-family:'Inter',sans-serif;\n  font-size:12.5px;\n  padding:8px 12px;\n  border-radius:8px;\n  width:220px;\n  outline:none;\n}\n.shop-search:focus{border-color:var(--navy);}\n.shop-search::placeholder{color:var(--muted);}\n\n/* ===== KPI cards ===== */\n.kpi-row{\n  display:grid;\n  grid-template-columns:repeat(4,1fr);\n  gap:16px;\n  margin-top:22px;\n}\n.kpi-card{\n  background:var(--surface);\n  border:1px solid var(--line);\n  border-radius:var(--radius);\n  padding:18px 20px;\n  box-shadow:var(--shadow);\n  border-top:3px solid var(--navy);\n}\n.kpi-card.c2{border-top-color:var(--accent);}\n.kpi-card.c3{border-top-color:var(--teal);}\n.kpi-card.c4{border-top-color:var(--amber);}\n.kpi-label{font-size:11px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:var(--muted);}\n.kpi-value{\n  font-family:'Space Grotesk',sans-serif;\n  font-size:30px;font-weight:700;color:var(--ink);\n  margin-top:8px;\n}\n.kpi-unit{font-size:14px;color:var(--muted);font-weight:500;margin-left:4px;}\n\n/* ===== Section cards ===== */\n.grid-2{display:grid;grid-template-columns:1.35fr 1fr;gap:16px;margin-top:16px;}\n.grid-2b{display:grid;grid-template-columns:1fr 1.2fr;gap:16px;margin-top:16px;}\n.panel{\n  background:var(--surface);\n  border:1px solid var(--line);\n  border-radius:var(--radius);\n  box-shadow:var(--shadow);\n  padding:20px 22px 22px;\n}\n.panel-head{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:14px;flex-wrap:wrap;gap:6px;}\n.panel-title{\n  font-family:'Space Grotesk',sans-serif;\n  font-size:15px;font-weight:600;color:var(--ink);\n}\n.panel-hint{font-size:11.5px;color:var(--muted);}\n.chart-box{position:relative;height:260px;}\n.chart-box.tall{height:340px;}\n\n/* ===== Area bars (custom horizontal chart) ===== */\n.area-list{display:flex;flex-direction:column;gap:9px;margin-top:4px;}\n.area-row{display:grid;grid-template-columns:150px 1fr 82px;align-items:center;gap:10px;cursor:pointer;padding:4px 6px;border-radius:8px;}\n.area-row:hover{background:#F7F8FC;}\n.area-row.active{background:var(--accent-soft);}\n.area-name{font-size:12.5px;color:var(--ink-soft);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}\n.area-row.active .area-name{color:var(--accent);font-weight:600;}\n.area-track{background:#EEF0F6;border-radius:6px;height:10px;overflow:hidden;}\n.area-fill{background:linear-gradient(90deg,var(--navy),var(--accent));height:100%;border-radius:6px;transition:width .25s ease;}\n.area-val{font-size:12px;text-align:right;color:var(--ink-soft);}\n\n/* ===== Leaderboard table ===== */\n.lb-scroll{max-height:560px; overflow-y:auto; border:1px solid var(--line); border-radius:10px;}\ntable.lb{width:100%;border-collapse:collapse;font-size:12.8px;}\ntable.lb th{\n  text-align:left;font-size:10.5px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;\n  color:var(--muted);border-bottom:1px solid var(--line);padding:8px 10px;cursor:pointer;user-select:none;\n  position:sticky; top:0; background:var(--surface); z-index:2;\n}\ntable.lb th.num,table.lb td.num{text-align:right;}\ntable.lb th:hover{color:var(--ink);}\ntable.lb td{padding:9px 10px;border-bottom:1px solid #F0F1F6;color:var(--ink-soft);}\ntable.lb tr:hover td{background:#F9FAFC;}\ntable.lb tr.zero-row td{color:var(--muted);}\ntable.lb tr.zero-row .shop-name{color:var(--ink-soft); font-weight:500;}\ntable.lb tr.zero-row .rank-badge{background:#EEF0F6; color:var(--muted);}\n.rank-badge{\n  display:inline-flex;align-items:center;justify-content:center;\n  width:22px;height:22px;border-radius:6px;\n  font-size:11px;font-weight:700;color:#fff;background:var(--muted);\n}\n.rank-badge.r1{background:var(--accent);}\n.rank-badge.r2{background:var(--amber);}\n.rank-badge.r3{background:var(--teal);}\n.shop-name{color:var(--ink);font-weight:600;}\n.bar-cell{position:relative;}\n.bar-cell .track{position:absolute;left:10px;right:10px;bottom:2px;height:3px;background:#EEF0F6;border-radius:3px;}\n.bar-cell .fill{position:absolute;left:10px;bottom:2px;height:3px;background:var(--teal);border-radius:3px;}\n\nfooter{max-width:1360px;margin:0 auto;padding:0 36px 40px;color:var(--muted);font-size:11.5px;}\n\n/* ===== Section title row (report section breaks) ===== */\n.section-title-row{\n  display:flex; align-items:center; gap:14px;\n  margin:28px 0 4px;\n}\n.section-title-eyebrow{\n  font-family:'Space Grotesk',sans-serif;\n  font-size:13px; font-weight:700; letter-spacing:.04em;\n  color:var(--navy);\n  white-space:nowrap;\n}\n.section-title-row::after{\n  content:'';\n  flex:1;\n  height:1px;\n  background:var(--line);\n}\n\n/* ===== Model panel toggle ===== */\n.model-toggle{display:flex; gap:7px; margin-bottom:10px;}\n.model-toggle .chip{padding:5px 12px; font-size:11.5px;}\n\n/* ===== Tab bar (page switcher) ===== */\n.tabbar{display:flex; gap:8px;}\n.tab-btn{\n  background:rgba(255,255,255,0.08);\n  border:1px solid rgba(255,255,255,0.16);\n  color:#C9CFE6;\n  font-family:'Inter',sans-serif;\n  font-size:13px; font-weight:600;\n  padding:9px 18px;\n  border-radius:9px;\n  cursor:pointer;\n  transition:all .12s ease;\n}\n.tab-btn:hover{border-color:rgba(255,255,255,0.32); color:#fff;}\n.tab-btn.active{\n  background:#fff;\n  color:var(--navy);\n  border-color:#fff;\n}\n\n/* ===== Page show/hide ===== */\n.page{display:none;}\n.page.active{display:block;}\n\n/* ===== Scope line (per-page summary pill, sits above filter bar) ===== */\n.scope-line{margin:-18px 0 14px; position:relative; z-index:6;}\n.scope-line .scope-pill{\n  display:inline-block;\n  background:var(--surface);\n  border:1px solid var(--line);\n  border-radius:999px;\n  padding:7px 16px;\n  font-size:12.5px;\n  color:var(--ink-soft);\n  box-shadow:var(--shadow);\n}\n.scope-line .scope-pill b{color:var(--navy); font-family:'IBM Plex Mono',monospace;}\n\n@media (max-width:1000px){\n  .kpi-row{grid-template-columns:repeat(2,1fr);}\n  .grid-2,.grid-2b{grid-template-columns:1fr;}\n  .topbar,.wrap{padding-left:20px;padding-right:20px;}\n}\n\n/* ===== Trend Performance: Summary Banner ===== */\n.trend-banner{\n  background:var(--surface);\n  border:1px solid var(--line);\n  border-radius:var(--radius);\n  box-shadow:var(--shadow);\n  padding:22px 24px 24px;\n  margin-bottom:16px;\n}\n.trend-banner-top{display:flex; justify-content:space-between; align-items:baseline; margin-bottom:16px; flex-wrap:wrap; gap:8px;}\n.trend-banner-eyebrow{\n  font-family:'Space Grotesk',sans-serif; font-size:15px; font-weight:700; color:var(--navy);\n}\n.trend-dataof{font-size:12px; color:var(--muted); margin-left:12px;}\n.trend-summary-grid{display:grid; grid-template-columns:1.1fr 1fr; gap:24px; align-items:start;}\n\n.mom-kpi-row{display:flex; align-items:center; gap:14px; flex-wrap:wrap;}\n.mom-kpi-card{\n  background:#F8F9FC; border:1px solid var(--line); border-radius:10px;\n  padding:12px 18px; min-width:140px;\n}\n.mom-kpi-card.highlight{background:var(--teal-soft); border-color:#BFE7DC;}\n.mom-kpi-label{font-size:10.5px; font-weight:600; letter-spacing:.06em; text-transform:uppercase; color:var(--muted);}\n.mom-kpi-value{font-family:'Space Grotesk',sans-serif; font-size:22px; font-weight:700; color:var(--ink); margin-top:4px;}\n.mom-kpi-arrow{font-size:18px; color:var(--muted);}\n\n.tier-row{display:flex; gap:10px; flex-wrap:wrap; margin-top:18px;}\n.tier-badge{\n  border-radius:10px; padding:10px 16px; min-width:96px;\n  border:1px solid var(--line); background:#fff;\n}\n.tier-badge .tier-count{font-family:'Space Grotesk',sans-serif; font-size:20px; font-weight:700;}\n.tier-badge .tier-label{font-size:10.5px; font-weight:600; color:var(--ink-soft); margin-top:2px;}\n.tier-badge.tier-neg{background:#FDEDEC; border-color:#F6C6C0;}\n.tier-badge.tier-neg .tier-count{color:#C0392B;}\n.tier-badge.tier-low{background:#FEF6E7; border-color:#F7DFA5;}\n.tier-badge.tier-low .tier-count{color:#B7791F;}\n.tier-badge.tier-mid{background:#FFF9E0; border-color:#F2E6A0;}\n.tier-badge.tier-mid .tier-count{color:#9C7C0A;}\n.tier-badge.tier-high{background:#EAF7EE; border-color:#B8E4C6;}\n.tier-badge.tier-high .tier-count{color:#1E8449;}\n.tier-badge.tier-vhigh{background:#E3F3EC; border-color:#9CD9BC;}\n.tier-badge.tier-vhigh .tier-count{color:#137A4B;}\n\n.trend-summary-right .chart-box{height:220px; margin-top:6px;}\n\n/* ===== Trend table panel ===== */\n.trend-table-panel{padding-bottom:14px;}\n.trend-filterbar{display:flex; gap:14px; flex-wrap:wrap; align-items:flex-end; margin:4px 0 16px;}\n.dropdown{\n  border:1px solid var(--line); background:#fff; color:var(--ink);\n  font-family:'Inter',sans-serif; font-size:12.5px; padding:8px 10px;\n  border-radius:8px; min-width:150px; outline:none;\n}\n.dropdown:focus{border-color:var(--navy);}\n\n/* ===== Multi-select dropdown (checkbox panel) ===== */\n.msdd{position:relative; display:inline-block;}\n.msdd-btn{\n  border:1px solid var(--line); background:#fff; color:var(--ink);\n  font-family:'Inter',sans-serif; font-size:12.5px; padding:8px 12px;\n  border-radius:8px; min-width:150px; max-width:220px; text-align:left;\n  cursor:pointer; display:flex; justify-content:space-between; align-items:center; gap:8px;\n  white-space:nowrap; overflow:hidden; text-overflow:ellipsis;\n}\n.msdd-btn:hover{border-color:var(--navy);}\n.msdd-btn.has-selection{border-color:var(--navy); background:#F5F7FC; color:var(--navy); font-weight:600;}\n.msdd-panel{\n  display:none; position:absolute; top:calc(100% + 6px); left:0; z-index:30;\n  background:#fff; border:1px solid var(--line); border-radius:10px;\n  box-shadow:var(--shadow); width:250px; max-height:290px; overflow-y:auto; padding:8px;\n}\n.msdd-panel.open{display:block;}\n.msdd-actions{\n  display:flex; justify-content:space-between; align-items:center;\n  font-size:11px; color:var(--muted); padding:2px 6px 8px; margin-bottom:6px;\n  border-bottom:1px solid var(--line);\n}\n.msdd-actions a{color:var(--navy); cursor:pointer; font-weight:600;}\n.msdd-actions a:hover{text-decoration:underline;}\n.msdd-search{\n  width:100%; box-sizing:border-box; border:1px solid var(--line); border-radius:6px;\n  padding:6px 8px; font-size:12px; margin-bottom:6px; outline:none;\n}\n.msdd-search:focus{border-color:var(--navy);}\n.msdd-item{\n  display:flex; align-items:center; gap:8px; padding:6px 8px; border-radius:6px;\n  font-size:12.5px; color:var(--ink-soft); cursor:pointer;\n}\n.msdd-item:hover{background:#F3F6FB;}\n.msdd-item input{accent-color:var(--navy); cursor:pointer;}\n.msdd-empty{font-size:12px; color:var(--muted); padding:8px; text-align:center;}\n\n.mom-table-wrap{max-height:600px; overflow:auto; border:1px solid var(--line); border-radius:10px; position:relative;}\ntable.mom-table{border-collapse:separate; border-spacing:0; font-size:12px; width:max-content; min-width:100%;}\ntable.mom-table th, table.mom-table td{padding:8px 10px; border-bottom:1px solid #F0F1F6; white-space:nowrap;}\ntable.mom-table thead th{\n  position:sticky; top:0; z-index:3; background:var(--navy); color:#fff;\n  font-size:10px; font-weight:700; letter-spacing:.05em; text-transform:uppercase; text-align:right;\n  border-bottom:none;\n}\ntable.mom-table thead th.col-shop{text-align:left;}\ntable.mom-table th.col-shop, table.mom-table td.col-shop{\n  position:sticky; left:0; z-index:2; background:#fff;\n  text-align:left; min-width:220px; max-width:220px; white-space:normal;\n  box-shadow:2px 0 4px -2px rgba(16,27,61,0.12);\n}\ntable.mom-table thead th.col-shop{background:var(--navy); z-index:4;}\ntable.mom-table td{text-align:right; color:var(--ink-soft); font-family:'IBM Plex Mono',monospace; font-size:11.5px;}\ntable.mom-table td.col-meta{font-family:'Inter',sans-serif; color:var(--ink-soft); font-size:11.5px;}\ntable.mom-table tbody tr:nth-child(even) td{background:#FAFBFD;}\ntable.mom-table tbody tr:nth-child(even) td.col-shop{background:#FAFBFD;}\ntable.mom-table tbody tr:hover td{background:#F3F6FB;}\ntable.mom-table tbody tr:hover td.col-shop{background:#F3F6FB;}\ntable.mom-table td.col-highlight{font-weight:700; color:var(--ink); background:#F5F8FF;}\ntable.mom-table tbody tr:nth-child(even) td.col-highlight{background:#EFF3FC;}\ntable.mom-table td.col-mom{font-weight:700; border-radius:6px;}\ntable.mom-table td.col-trend{padding:4px 10px;}\n.spark-svg{display:block;}\n"
BODY = '<div class="topbar">\n  <div class="topbar-inner">\n    <div>\n      <p class="brand-eyebrow">TSM · Retail Performance</p>\n      <h1 class="brand-title">Retail Sales Performance Dashboard</h1>\n      <p class="brand-sub">Hall &amp; COCO shops · Refresh_TSM.xlsx</p>\n    </div>\n    <div class="tabbar" id="tabbar">\n      <button class="tab-btn active" data-page="handset">📱 Handset</button>\n      <button class="tab-btn" data-page="accessories">🎧 Accessories</button>\n      <button class="tab-btn" data-page="trend">📈 Trend Performance</button>\n    </div>\n  </div>\n</div>\n\n<div class="wrap">\n\n  <div class="page active" id="page-handset">\n\n    <div class="scope-line">\n      <span class="scope-pill" id="handset-scopePill">Loading scope…</span>\n    </div>\n\n    <div class="filterbar">\n      <div class="filter-group">\n        <span class="filter-label">Region</span>\n        <div class="chip-row" id="handset-regionChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Shop Type</span>\n        <div class="chip-row" id="handset-typeChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Area <span class="filter-label-hint">(select multiple)</span></span>\n        <div class="chip-row" id="handset-areaChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Date</span>\n        <div class="chip-row" id="handset-dateChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Shop <span class="filter-label-hint">(type to search)</span></span>\n        <input class="shop-search" id="handset-shopSelect" list="handset-shopList" type="text" placeholder="All shops" autocomplete="off">\n        <datalist id="handset-shopList"></datalist>\n      </div>\n      <button class="reset-btn" id="handset-resetBtn">Reset filters</button>\n    </div>\n\n    <div class="kpi-row">\n      <div class="kpi-card c1">\n        <div class="kpi-label">Total Handset Volume</div>\n        <div class="kpi-value num" id="handset-kpiQty">0<span class="kpi-unit">units</span></div>\n      </div>\n      <div class="kpi-card c2">\n        <div class="kpi-label">Total Handset Revenue</div>\n        <div class="kpi-value num" id="handset-kpiRev">0<span class="kpi-unit">THB</span></div>\n      </div>\n      <div class="kpi-card c3">\n        <div class="kpi-label">Avg. Selling Price</div>\n        <div class="kpi-value num" id="handset-kpiAvg">0<span class="kpi-unit">THB/unit</span></div>\n      </div>\n      <div class="kpi-card c4">\n        <div class="kpi-label">Active Shops</div>\n        <div class="kpi-value num" id="handset-kpiShops">0<span class="kpi-unit">of 61</span></div>\n      </div>\n    </div>\n\n    <div class="grid-2">\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Daily Sales Trend</span>\n          <span class="panel-hint">Volume (bars) &amp; Revenue (line)</span>\n        </div>\n        <div class="chart-box"><canvas id="handset-trendChart"></canvas></div>\n      </div>\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Regional Performance</span>\n          <span class="panel-hint">Click a bar to drill in</span>\n        </div>\n        <div class="chart-box"><canvas id="handset-regionChart"></canvas></div>\n      </div>\n    </div>\n\n    <div class="grid-2b">\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Area Drill-down</span>\n          <span class="panel-hint" id="handset-areaHint">All regions</span>\n        </div>\n        <div class="area-list" id="handset-areaList"></div>\n      </div>\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Shop Leaderboard — Top 61</span>\n          <span class="panel-hint" id="handset-lbHint">Click a column to sort</span>\n        </div>\n        <div class="lb-scroll">\n          <table class="lb">\n            <thead>\n              <tr>\n                <th style="width:34px;">#</th>\n                <th>Shop</th>\n                <th>Region / Area</th>\n                <th class="num" data-sort="qty">Qty</th>\n                <th class="num" data-sort="rev">Revenue (THB)</th>\n              </tr>\n            </thead>\n            <tbody id="handset-lbBody"></tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <div class="section-title-row">\n      <span class="section-title-eyebrow">Brand &amp; Model Performance</span>\n    </div>\n\n    <div class="grid-2b">\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Brand Market Share</span>\n          <span class="panel-hint">Volume share vs. Revenue share</span>\n        </div>\n        <div class="chart-box"><canvas id="handset-brandChart"></canvas></div>\n      </div>\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Top Models (Hero SKUs) &amp; Volume Leaders</span>\n          <span class="panel-hint" id="handset-modelHint">Sorted by revenue</span>\n        </div>\n        <div class="model-toggle">\n          <button class="chip active" id="handset-modelByRev">By Revenue</button>\n          <button class="chip" id="handset-modelByQty">By Volume</button>\n        </div>\n        <div class="chart-box tall"><canvas id="handset-modelChart"></canvas></div>\n      </div>\n    </div>\n\n  </div>\n\n\n  <div class="page" id="page-accessories">\n\n    <div class="scope-line">\n      <span class="scope-pill" id="accessories-scopePill">Loading scope…</span>\n    </div>\n\n    <div class="filterbar">\n      <div class="filter-group">\n        <span class="filter-label">Region</span>\n        <div class="chip-row" id="accessories-regionChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Shop Type</span>\n        <div class="chip-row" id="accessories-typeChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Area <span class="filter-label-hint">(select multiple)</span></span>\n        <div class="chip-row" id="accessories-areaChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Date</span>\n        <div class="chip-row" id="accessories-dateChips"></div>\n      </div>\n      <div class="filter-group">\n        <span class="filter-label">Shop <span class="filter-label-hint">(type to search)</span></span>\n        <input class="shop-search" id="accessories-shopSelect" list="accessories-shopList" type="text" placeholder="All shops" autocomplete="off">\n        <datalist id="accessories-shopList"></datalist>\n      </div>\n      <button class="reset-btn" id="accessories-resetBtn">Reset filters</button>\n    </div>\n\n    <div class="kpi-row">\n      <div class="kpi-card c1">\n        <div class="kpi-label">Total Accessory Volume</div>\n        <div class="kpi-value num" id="accessories-kpiQty">0<span class="kpi-unit">units</span></div>\n      </div>\n      <div class="kpi-card c2">\n        <div class="kpi-label">Total Accessory Revenue</div>\n        <div class="kpi-value num" id="accessories-kpiRev">0<span class="kpi-unit">THB</span></div>\n      </div>\n      <div class="kpi-card c3">\n        <div class="kpi-label">Avg. Selling Price</div>\n        <div class="kpi-value num" id="accessories-kpiAvg">0<span class="kpi-unit">THB/unit</span></div>\n      </div>\n      <div class="kpi-card c4">\n        <div class="kpi-label">Active Shops</div>\n        <div class="kpi-value num" id="accessories-kpiShops">0<span class="kpi-unit">of 61</span></div>\n      </div>\n    </div>\n\n    <div class="grid-2">\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Daily Sales Trend</span>\n          <span class="panel-hint">Volume (bars) &amp; Revenue (line)</span>\n        </div>\n        <div class="chart-box"><canvas id="accessories-trendChart"></canvas></div>\n      </div>\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Regional Performance</span>\n          <span class="panel-hint">Click a bar to drill in</span>\n        </div>\n        <div class="chart-box"><canvas id="accessories-regionChart"></canvas></div>\n      </div>\n    </div>\n\n    <div class="grid-2b">\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Area Drill-down</span>\n          <span class="panel-hint" id="accessories-areaHint">All regions</span>\n        </div>\n        <div class="area-list" id="accessories-areaList"></div>\n      </div>\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Shop Leaderboard — Top 61</span>\n          <span class="panel-hint" id="accessories-lbHint">Click a column to sort</span>\n        </div>\n        <div class="lb-scroll">\n          <table class="lb">\n            <thead>\n              <tr>\n                <th style="width:34px;">#</th>\n                <th>Shop</th>\n                <th>Region / Area</th>\n                <th class="num" data-sort="qty">Qty</th>\n                <th class="num" data-sort="rev">Revenue (THB)</th>\n              </tr>\n            </thead>\n            <tbody id="accessories-lbBody"></tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <div class="section-title-row">\n      <span class="section-title-eyebrow">Brand &amp; Product Performance</span>\n    </div>\n\n    <div class="grid-2b">\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Brand Market Share</span>\n          <span class="panel-hint">Volume share vs. Revenue share</span>\n        </div>\n        <div class="chart-box"><canvas id="accessories-brandChart"></canvas></div>\n      </div>\n      <div class="panel">\n        <div class="panel-head">\n          <span class="panel-title">Top Products (Best Sellers) &amp; Volume Leaders</span>\n          <span class="panel-hint" id="accessories-modelHint">Sorted by revenue</span>\n        </div>\n        <div class="model-toggle">\n          <button class="chip active" id="accessories-modelByRev">By Revenue</button>\n          <button class="chip" id="accessories-modelByQty">By Volume</button>\n        </div>\n        <div class="chart-box tall"><canvas id="accessories-modelChart"></canvas></div>\n      </div>\n    </div>\n\n  </div>\n\n\n  <div class="page" id="page-trend">\n\n    <div class="trend-banner">\n      <div class="trend-banner-top">\n        <div>\n          <span class="trend-banner-eyebrow">Trend Performance · Month-over-Month</span>\n          <span class="trend-dataof" id="trend-dataOf">Data as of —</span>\n        </div>\n      </div>\n\n      <div class="trend-summary-grid">\n        <div class="trend-summary-left">\n          <div class="mom-kpi-row">\n            <div class="mom-kpi-card">\n              <div class="mom-kpi-label" id="trend-prevLabel">Previous month</div>\n              <div class="mom-kpi-value num" id="trend-prevTotal">0</div>\n            </div>\n            <div class="mom-kpi-arrow">→</div>\n            <div class="mom-kpi-card">\n              <div class="mom-kpi-label" id="trend-currLabel">Current month</div>\n              <div class="mom-kpi-value num" id="trend-currTotal">0</div>\n            </div>\n            <div class="mom-kpi-card highlight">\n              <div class="mom-kpi-label">Overall MOM</div>\n              <div class="mom-kpi-value num" id="trend-overallMom">0%</div>\n            </div>\n          </div>\n\n          <div class="tier-row" id="trend-tierRow"></div>\n        </div>\n\n        <div class="trend-summary-right">\n          <div class="panel-head">\n            <span class="panel-title" id="trend-chartTitle">Overall Trend (all shops)</span>\n            <span class="panel-hint" id="trend-chartHint"></span>\n          </div>\n          <div class="chart-box"><canvas id="trend-overallChart"></canvas></div>\n        </div>\n      </div>\n    </div>\n\n    <div class="panel trend-table-panel">\n      <div class="panel-head">\n        <span class="panel-title">Shop-level Trend Table</span>\n        <span class="panel-hint" id="trend-tableHint">61 shops</span>\n      </div>\n\n      <div class="trend-filterbar">\n        <div class="filter-group">\n          <span class="filter-label">Region</span>\n          <div class="msdd" id="trend-fRegion">\n            <button class="msdd-btn" id="trend-fRegion-btn" type="button">All ▾</button>\n            <div class="msdd-panel" id="trend-fRegion-panel"></div>\n          </div>\n        </div>\n        <div class="filter-group">\n          <span class="filter-label">Area</span>\n          <div class="msdd" id="trend-fArea">\n            <button class="msdd-btn" id="trend-fArea-btn" type="button">All ▾</button>\n            <div class="msdd-panel" id="trend-fArea-panel"></div>\n          </div>\n        </div>\n        <div class="filter-group">\n          <span class="filter-label">Shop Type</span>\n          <div class="msdd" id="trend-fType">\n            <button class="msdd-btn" id="trend-fType-btn" type="button">All ▾</button>\n            <div class="msdd-panel" id="trend-fType-panel"></div>\n          </div>\n        </div>\n        <div class="filter-group">\n          <span class="filter-label">Shop Name</span>\n          <div class="msdd" id="trend-fShop">\n            <button class="msdd-btn" id="trend-fShop-btn" type="button">All ▾</button>\n            <div class="msdd-panel" id="trend-fShop-panel"></div>\n          </div>\n        </div>\n        <div class="filter-group">\n          <span class="filter-label">Tier MOM</span>\n          <div class="msdd" id="trend-fTier">\n            <button class="msdd-btn" id="trend-fTier-btn" type="button">All ▾</button>\n            <div class="msdd-panel" id="trend-fTier-panel"></div>\n          </div>\n        </div>\n        <button class="export-btn" id="trend-exportBtn">⬇ Export CSV</button>\n        <button class="reset-btn" id="trend-resetBtn">Reset filters</button>\n      </div>\n\n      <div class="mom-table-wrap" id="trend-tableWrap">\n        <table class="mom-table" id="trend-table">\n          <thead>\n            <tr id="trend-headRow"></tr>\n          </thead>\n          <tbody id="trend-tbody"></tbody>\n        </table>\n      </div>\n    </div>\n\n  </div>\n\n</div>\n<footer>Retail Sales Performance Dashboard · Source: Refresh_TSM.xlsx · Filters apply instantly across all views.</footer>\n'
JS = '// =====================================================================\n// createDashboard(cfg) builds one fully independent dashboard page.\n// cfg: { prefix, data, shopsMaster, unitLabel }\n// Called once per product-group page (Handset, Accessories, ...).\n// =====================================================================\nfunction createDashboard(cfg){\n  const PFX = cfg.prefix;\n  const RAW_DATA = cfg.data;\n  const SHOPS_MASTER = cfg.shopsMaster || [];\n  const UNIT_LABEL = cfg.unitLabel || \'unit\';\n\n  const $ = (id) => document.getElementById(PFX + \'-\' + id);\n  const pageEl = document.getElementById(\'page-\' + PFX);\n\n  // ---------- Setup ----------\n  const REGIONS = [...new Set(RAW_DATA.map(d=>d.region))].sort();\n  const AREA_TO_REGION = {};\n  RAW_DATA.forEach(d=>{AREA_TO_REGION[d.area]=d.region;});\n  const ALL_AREAS = REGIONS.flatMap(r =>\n    Object.keys(AREA_TO_REGION).filter(a=>AREA_TO_REGION[a]===r).sort()\n  );\n  const DATES = [...new Set(RAW_DATA.map(d=>d.date))].sort();\n  const TYPES = [...new Set(RAW_DATA.map(d=>d.type))].sort();\n  const TOTAL_SHOPS = (SHOPS_MASTER && SHOPS_MASTER.length) ? SHOPS_MASTER.length : new Set(RAW_DATA.map(d=>d.shop)).size;\n\n  // Full shop universe for the search filter: master list ∪ any shop codes\n  // seen in the data but missing from the master list.\n  const SHOP_LOOKUP = {}; // code -> {code, name, region, area, type}\n  (SHOPS_MASTER||[]).forEach(s=>{\n    SHOP_LOOKUP[s.code] = {code:s.code, name:s.name, region:s.region, area:s.area, type:s.type};\n  });\n  RAW_DATA.forEach(d=>{\n    if(!SHOP_LOOKUP[d.code]) SHOP_LOOKUP[d.code] = {code:d.code, name:d.shop, region:d.region, area:d.area, type:d.type};\n  });\n  const SHOP_NAME_TO_CODE = {};\n  Object.values(SHOP_LOOKUP).forEach(s=>{ SHOP_NAME_TO_CODE[s.name] = s.code; });\n  const ALL_SHOP_NAMES = Object.values(SHOP_LOOKUP).map(s=>s.name).sort();\n\n  const fmtInt = n => Math.round(n).toLocaleString(\'en-US\');\n  const fmtDate = s => {\n    const d = new Date(s+\'T00:00:00\');\n    return d.toLocaleDateString(\'en-GB\',{day:\'2-digit\',month:\'short\'});\n  };\n\n  const state = {\n    region: \'All\',\n    type: \'All\',\n    areas: new Set(), // empty set = "All areas"\n    shop: \'All\', // shop code, or \'All\'\n    dates: new Set(DATES),\n    sortKey: \'rev\',\n    sortDir: \'desc\',\n    modelSortBy: \'rev\'\n  };\n\n  function pruneAreasForRegion(){\n    if(state.region===\'All\') return;\n    [...state.areas].forEach(a=>{\n      if(AREA_TO_REGION[a]!==state.region) state.areas.delete(a);\n    });\n  }\n\n  function pruneShopForFilters(){\n    if(state.shop===\'All\') return;\n    const s = SHOP_LOOKUP[state.shop];\n    if(!s) { state.shop=\'All\'; return; }\n    const ok = (state.region===\'All\' || s.region===state.region) &&\n               (state.type===\'All\' || s.type===state.type) &&\n               (state.areas.size===0 || state.areas.has(s.area));\n    if(!ok) state.shop=\'All\';\n  }\n\n  // ---------- Shop search (type-ahead filter, single shop) ----------\n  function renderShopSearch(){\n    const datalistEl = $(\'shopList\');\n    if(datalistEl.childElementCount===0){\n      ALL_SHOP_NAMES.forEach(name=>{\n        const opt = document.createElement(\'option\');\n        opt.value = name;\n        datalistEl.appendChild(opt);\n      });\n    }\n    const input = $(\'shopSelect\');\n    input.value = state.shop===\'All\' ? \'\' : (SHOP_LOOKUP[state.shop] ? SHOP_LOOKUP[state.shop].name : \'\');\n  }\n\n  const shopInput = $(\'shopSelect\');\n  function applyShopInput(){\n    const typed = shopInput.value.trim();\n    if(typed===\'\'){ if(state.shop!==\'All\'){ state.shop=\'All\'; renderAll(); } return; }\n    const code = SHOP_NAME_TO_CODE[typed];\n    if(code && code!==state.shop){\n      state.shop = code;\n      const s = SHOP_LOOKUP[code];\n      // keep other filters consistent with the chosen shop\n      if(state.region!==\'All\' && s.region!==state.region) state.region=\'All\';\n      if(state.type!==\'All\' && s.type!==state.type) state.type=\'All\';\n      state.areas.clear();\n      renderAll();\n      shopInput.blur(); // close the native datalist popup immediately once matched\n    }\n    // if typed text doesn\'t match any known shop exactly, leave state.shop\n    // as-is (user is likely still typing) -- input keeps their text until blur.\n  }\n  // \'input\' fires per keystroke so a selection commits the instant it matches\n  // (avoids a stuck native datalist popup swallowing the next click elsewhere).\n  shopInput.addEventListener(\'input\', applyShopInput);\n  shopInput.addEventListener(\'change\', applyShopInput);\n  shopInput.addEventListener(\'blur\', ()=>{\n    if(shopInput.value.trim()===\'\' && state.shop!==\'All\'){ state.shop=\'All\'; renderAll(); }\n    else if(shopInput.value.trim()!==\'\' && !SHOP_NAME_TO_CODE[shopInput.value.trim()]){\n      // typed text that never matched a real shop -- revert to current selection\n      shopInput.value = state.shop===\'All\' ? \'\' : (SHOP_LOOKUP[state.shop] ? SHOP_LOOKUP[state.shop].name : \'\');\n    }\n  });\n\n  // ---------- Chip rendering ----------\n  function renderRegionChips(){\n    const el = $(\'regionChips\');\n    el.innerHTML = \'\';\n    [\'All\', ...REGIONS].forEach(r=>{\n      const chip = document.createElement(\'button\');\n      chip.className = \'chip\' + (state.region===r ? \' active\':\'\');\n      chip.textContent = r;\n      chip.onclick = ()=>{\n        state.region = (state.region===r && r!==\'All\') ? \'All\' : r;\n        pruneAreasForRegion();\n        pruneShopForFilters();\n        renderAll();\n      };\n      el.appendChild(chip);\n    });\n  }\n\n  function renderTypeChips(){\n    const el = $(\'typeChips\');\n    el.innerHTML = \'\';\n    [\'All\', ...TYPES].forEach(t=>{\n      const chip = document.createElement(\'button\');\n      chip.className = \'chip\' + (state.type===t ? \' active\':\'\');\n      chip.textContent = t;\n      chip.onclick = ()=>{\n        state.type = (state.type===t && t!==\'All\') ? \'All\' : t;\n        pruneShopForFilters();\n        renderAll();\n      };\n      el.appendChild(chip);\n    });\n  }\n\n  function renderAreaChips(){\n    const el = $(\'areaChips\');\n    el.innerHTML = \'\';\n    const areas = state.region===\'All\' ? ALL_AREAS : ALL_AREAS.filter(a=>AREA_TO_REGION[a]===state.region);\n    const chip = document.createElement(\'button\');\n    chip.className=\'chip\'+(state.areas.size===0?\' active\':\'\');\n    chip.textContent=\'All\';\n    chip.onclick=()=>{state.areas.clear(); pruneShopForFilters(); renderAll();};\n    el.appendChild(chip);\n    areas.forEach(a=>{\n      const c = document.createElement(\'button\');\n      c.className=\'chip\'+(state.areas.has(a)?\' active\':\'\');\n      c.textContent = a;\n      c.title = a;\n      c.onclick=()=>{\n        if(state.areas.has(a)) state.areas.delete(a);\n        else state.areas.add(a);\n        pruneShopForFilters();\n        renderAll();\n      };\n      el.appendChild(c);\n    });\n  }\n\n  function renderDateChips(){\n    const el = $(\'dateChips\');\n    el.innerHTML=\'\';\n    DATES.forEach(d=>{\n      const c = document.createElement(\'button\');\n      c.className=\'chip date\'+(state.dates.has(d)?\' active\':\'\');\n      c.textContent = fmtDate(d);\n      c.onclick=()=>{\n        if(state.dates.has(d)){ if(state.dates.size>1) state.dates.delete(d); }\n        else state.dates.add(d);\n        renderAll();\n      };\n      el.appendChild(c);\n    });\n  }\n\n  // ---------- Filtering ----------\n  function getFiltered({useRegion=true, useArea=true, useDate=true, useType=true, useShop=true}={}){\n    return RAW_DATA.filter(d=>\n      (!useRegion || state.region===\'All\' || d.region===state.region) &&\n      (!useType || state.type===\'All\' || d.type===state.type) &&\n      (!useArea || state.areas.size===0 || state.areas.has(d.area)) &&\n      (!useShop || state.shop===\'All\' || d.code===state.shop) &&\n      (!useDate || state.dates.has(d.date))\n    );\n  }\n\n  // ---------- KPIs ----------\n  function renderKPIs(){\n    const f = getFiltered();\n    const qty = f.reduce((s,d)=>s+d.qty,0);\n    const rev = f.reduce((s,d)=>s+d.rev,0);\n    const avg = qty ? rev/qty : 0;\n    const shops = new Set(f.filter(d=>d.qty>0).map(d=>d.shop)).size;\n    $(\'kpiQty\').innerHTML = fmtInt(qty)+\'<span class="kpi-unit">\'+UNIT_LABEL+(qty===1?\'\':\'s\')+\'</span>\';\n    $(\'kpiRev\').innerHTML = fmtInt(rev)+\'<span class="kpi-unit">THB</span>\';\n    $(\'kpiAvg\').innerHTML = fmtInt(avg)+\'<span class="kpi-unit">THB/\'+UNIT_LABEL+\'</span>\';\n    $(\'kpiShops\').innerHTML = shops+\'<span class="kpi-unit">of \'+TOTAL_SHOPS+\'</span>\';\n\n    const scopeBits = [];\n    scopeBits.push(state.region===\'All\'?\'All regions\':state.region);\n    scopeBits.push(state.type===\'All\'?\'Hall & COCO\':state.type+\' only\');\n    if(state.areas.size===0) scopeBits.push(\'all areas\');\n    else if(state.areas.size===1) scopeBits.push([...state.areas][0]);\n    else scopeBits.push(state.areas.size+\' areas: \'+[...state.areas].join(\', \'));\n    if(state.shop!==\'All\' && SHOP_LOOKUP[state.shop]) scopeBits.push(\'Shop: \'+SHOP_LOOKUP[state.shop].name);\n    const dArr = [...state.dates].sort();\n    scopeBits.push(dArr.length===DATES.length ? \'full period\' : dArr.map(fmtDate).join(\', \'));\n    $(\'scopePill\').innerHTML =\n      \'Showing <b>\'+fmtInt(qty)+\'</b> \'+UNIT_LABEL+\'s · <b>฿\'+fmtInt(rev)+\'</b> — \'+scopeBits.join(\' · \');\n  }\n\n  // ---------- Charts (instances kept in this page\'s closure) ----------\n  let trendChart, regionChart, brandChart, modelChart;\n\n  function renderTrend(){\n    const f = getFiltered();\n    const qtyByDate = {}, revByDate = {};\n    DATES.forEach(d=>{qtyByDate[d]=0; revByDate[d]=0;});\n    f.forEach(d=>{qtyByDate[d.date]+=d.qty; revByDate[d.date]+=d.rev;});\n    const labels = DATES.map(fmtDate);\n    const qtyData = DATES.map(d=>qtyByDate[d]);\n    const revData = DATES.map(d=>revByDate[d]);\n\n    const ctx = $(\'trendChart\');\n    if(trendChart) trendChart.destroy();\n    trendChart = new Chart(ctx, {\n      data:{\n        labels,\n        datasets:[\n          {type:\'bar\', label:\'Volume (units)\', data:qtyData, backgroundColor:\'#101B3D\', borderRadius:6, yAxisID:\'y\', maxBarThickness:46},\n          {type:\'line\', label:\'Revenue (THB)\', data:revData, borderColor:\'#E8483C\', backgroundColor:\'#E8483C\', tension:.35, yAxisID:\'y1\', pointRadius:5, pointBackgroundColor:\'#E8483C\', borderWidth:2.5}\n        ]\n      },\n      options:{\n        responsive:true, maintainAspectRatio:false,\n        interaction:{mode:\'index\', intersect:false},\n        plugins:{legend:{position:\'bottom\', labels:{boxWidth:10,font:{size:11,family:\'Inter\'}}}},\n        scales:{\n          y:{position:\'left\', title:{display:true,text:\'Units\',font:{size:10}}, grid:{color:\'#EEF0F6\'}},\n          y1:{position:\'right\', title:{display:true,text:\'Revenue (THB)\',font:{size:10}}, grid:{display:false}}\n        }\n      }\n    });\n  }\n\n  function renderRegionChart(){\n    const f = getFiltered({useRegion:false});\n    const qtyByReg={}, revByReg={};\n    REGIONS.forEach(r=>{qtyByReg[r]=0; revByReg[r]=0;});\n    f.forEach(d=>{qtyByReg[d.region]+=d.qty; revByReg[d.region]+=d.rev;});\n\n    const ctx = $(\'regionChart\');\n    if(regionChart) regionChart.destroy();\n    regionChart = new Chart(ctx, {\n      type:\'bar\',\n      data:{\n        labels:REGIONS,\n        datasets:[\n          {label:\'Revenue (THB)\', data:REGIONS.map(r=>revByReg[r]), backgroundColor:REGIONS.map(r=> r===state.region?\'#E8483C\':\'#D9DEEB\'), borderRadius:6, yAxisID:\'y\'},\n          {label:\'Volume (units)\', data:REGIONS.map(r=>qtyByReg[r]), type:\'line\', borderColor:\'#1E9E86\', backgroundColor:\'#1E9E86\', yAxisID:\'y1\', pointRadius:5, borderWidth:2.5}\n        ]\n      },\n      options:{\n        responsive:true, maintainAspectRatio:false,\n        onClick:(evt,elements)=>{\n          if(elements.length){\n            const idx = elements[0].index;\n            const r = REGIONS[idx];\n            state.region = state.region===r ? \'All\' : r;\n            pruneAreasForRegion();\n            pruneShopForFilters();\n            renderAll();\n          }\n        },\n        plugins:{legend:{position:\'bottom\', labels:{boxWidth:10,font:{size:11,family:\'Inter\'}}}},\n        scales:{\n          y:{position:\'left\', title:{display:true,text:\'Revenue (THB)\',font:{size:10}}, grid:{color:\'#EEF0F6\'}},\n          y1:{position:\'right\', title:{display:true,text:\'Units\',font:{size:10}}, grid:{display:false}}\n        }\n      }\n    });\n  }\n\n  function renderBrandChart(){\n    const f = getFiltered();\n    const byBrand = {};\n    f.forEach(d=>{\n      if(!byBrand[d.brand]) byBrand[d.brand]={qty:0, rev:0};\n      byBrand[d.brand].qty += d.qty;\n      byBrand[d.brand].rev += d.rev;\n    });\n    let rows = Object.entries(byBrand).map(([brand,v])=>({brand, ...v})).filter(r=>r.qty>0);\n    rows.sort((a,b)=>b.rev-a.rev);\n\n    if(rows.length > 7){\n      const top = rows.slice(0,7);\n      const rest = rows.slice(7);\n      const otherQty = rest.reduce((s,r)=>s+r.qty,0);\n      const otherRev = rest.reduce((s,r)=>s+r.rev,0);\n      top.push({brand:\'Other\', qty:otherQty, rev:otherRev});\n      rows = top;\n    }\n    const totalQty = rows.reduce((s,r)=>s+r.qty,0) || 1;\n    const totalRev = rows.reduce((s,r)=>s+r.rev,0) || 1;\n    const labels = rows.map(r=>r.brand);\n    const qtyShare = rows.map(r=>+(r.qty/totalQty*100).toFixed(1));\n    const revShare = rows.map(r=>+(r.rev/totalRev*100).toFixed(1));\n\n    const ctx = $(\'brandChart\');\n    if(brandChart) brandChart.destroy();\n    brandChart = new Chart(ctx, {\n      type:\'bar\',\n      data:{\n        labels,\n        datasets:[\n          {label:\'Volume share (%)\', data:qtyShare, backgroundColor:\'#2a78d6\', borderRadius:4, maxBarThickness:22},\n          {label:\'Revenue share (%)\', data:revShare, backgroundColor:\'#eb6834\', borderRadius:4, maxBarThickness:22}\n        ]\n      },\n      options:{\n        responsive:true, maintainAspectRatio:false,\n        plugins:{legend:{position:\'bottom\', labels:{boxWidth:10,font:{size:11,family:\'Inter\'}}},\n          tooltip:{callbacks:{label:(c)=>c.dataset.label+\': \'+c.parsed.y+\'%\'}}},\n        scales:{\n          y:{beginAtZero:true, max:100, ticks:{callback:(v)=>v+\'%\'}, grid:{color:\'#EEF0F6\'}},\n          x:{grid:{display:false}}\n        }\n      }\n    });\n  }\n\n  function renderModelChart(){\n    const f = getFiltered();\n    const byModel = {};\n    f.forEach(d=>{\n      const key = d.brand+\' \'+d.model;\n      if(!byModel[key]) byModel[key] = {label:key, qty:0, rev:0};\n      byModel[key].qty += d.qty;\n      byModel[key].rev += d.rev;\n    });\n    let rows = Object.values(byModel).filter(r=>r.qty>0);\n    rows.sort((a,b)=> state.modelSortBy===\'rev\' ? b.rev-a.rev : b.qty-a.qty);\n    rows = rows.slice(0,8);\n\n    $(\'modelHint\').textContent = state.modelSortBy===\'rev\' ? \'Sorted by revenue\' : \'Sorted by volume\';\n    const values = rows.map(r=> state.modelSortBy===\'rev\' ? r.rev : r.qty);\n    const labels = rows.map(r=>r.label);\n    const barColor = state.modelSortBy===\'rev\' ? \'#199e70\' : \'#2a78d6\';\n\n    const ctx = $(\'modelChart\');\n    if(modelChart) modelChart.destroy();\n    modelChart = new Chart(ctx, {\n      type:\'bar\',\n      data:{\n        labels,\n        datasets:[{\n          label: state.modelSortBy===\'rev\' ? \'Revenue (THB)\' : \'Volume (units)\',\n          data: values,\n          backgroundColor: barColor,\n          borderRadius:4,\n          maxBarThickness:20\n        }]\n      },\n      options:{\n        indexAxis:\'y\',\n        responsive:true, maintainAspectRatio:false,\n        plugins:{legend:{display:false},\n          tooltip:{callbacks:{label:(c)=> state.modelSortBy===\'rev\' ? \'฿\'+c.parsed.x.toLocaleString() : c.parsed.x.toLocaleString()+\' units\'}}},\n        scales:{\n          x:{beginAtZero:true, ticks:{callback:(v)=> state.modelSortBy===\'rev\' ? (v/1000).toFixed(0)+\'K\' : v}, grid:{color:\'#EEF0F6\'}},\n          y:{grid:{display:false}}\n        }\n      }\n    });\n  }\n\n  $(\'modelByRev\').addEventListener(\'click\', ()=>{\n    state.modelSortBy = \'rev\';\n    $(\'modelByRev\').classList.add(\'active\');\n    $(\'modelByQty\').classList.remove(\'active\');\n    renderModelChart();\n  });\n  $(\'modelByQty\').addEventListener(\'click\', ()=>{\n    state.modelSortBy = \'qty\';\n    $(\'modelByQty\').classList.add(\'active\');\n    $(\'modelByRev\').classList.remove(\'active\');\n    renderModelChart();\n  });\n\n  // ---------- Area drill-down (custom bars) ----------\n  function renderAreaList(){\n    const f = getFiltered({useArea:false});\n    const areas = state.region===\'All\' ? ALL_AREAS : ALL_AREAS.filter(a=>AREA_TO_REGION[a]===state.region);\n    const rows = areas.map(a=>{\n      const rows_f = f.filter(d=>d.area===a);\n      return {area:a, qty:rows_f.reduce((s,d)=>s+d.qty,0), rev:rows_f.reduce((s,d)=>s+d.rev,0)};\n    }).sort((a,b)=>b.rev-a.rev);\n    const maxRev = Math.max(1, ...rows.map(r=>r.rev));\n\n    $(\'areaHint\').textContent = state.region===\'All\' ? \'All regions\' : state.region+\' region\';\n    const el = $(\'areaList\');\n    el.innerHTML = \'\';\n    rows.forEach(r=>{\n      const div = document.createElement(\'div\');\n      div.className = \'area-row\'+(state.areas.has(r.area)?\' active\':\'\');\n      div.innerHTML = `\n        <span class="area-name" title="${r.area}">${r.area}</span>\n        <span class="area-track"><span class="area-fill" style="width:${(r.rev/maxRev*100).toFixed(1)}%"></span></span>\n        <span class="area-val num">฿${fmtInt(r.rev)}</span>`;\n      div.onclick = ()=>{\n        if(state.areas.has(r.area)) state.areas.delete(r.area);\n        else state.areas.add(r.area);\n        pruneShopForFilters();\n        renderAll();\n      };\n      el.appendChild(div);\n    });\n  }\n\n  // ---------- Shop leaderboard (all shops, incl. zero-sale) ----------\n  function shopMatchesFilters(s){\n    return (state.region===\'All\' || s.region===state.region) &&\n           (state.type===\'All\' || s.type===state.type) &&\n           (state.areas.size===0 || state.areas.has(s.area)) &&\n           (state.shop===\'All\' || s.code===state.shop);\n  }\n\n  function renderLeaderboard(){\n    const f = getFiltered();\n\n    const universe = {};\n    (SHOPS_MASTER||[]).forEach(s=>{\n      universe[s.code] = {code:s.code, shop:s.name, region:s.region, area:s.area, type:s.type, qty:0, rev:0};\n    });\n    RAW_DATA.forEach(d=>{\n      if(!universe[d.code]) universe[d.code] = {code:d.code, shop:d.shop, region:d.region, area:d.area, type:d.type, qty:0, rev:0};\n    });\n\n    let rows = Object.values(universe).filter(shopMatchesFilters);\n    f.forEach(d=>{\n      if(universe[d.code]){\n        universe[d.code].qty += d.qty;\n        universe[d.code].rev += d.rev;\n      }\n    });\n\n    rows.sort((a,b)=> state.sortDir===\'desc\' ? b[state.sortKey]-a[state.sortKey] : a[state.sortKey]-b[state.sortKey]);\n    const maxRev = Math.max(1, ...rows.map(r=>r.rev));\n    const totalUniverse = Object.keys(universe).length;\n    const zeroCount = rows.filter(r=>r.qty===0).length;\n\n    $(\'lbHint\').textContent =\n      rows.length===totalUniverse\n        ? `${rows.length} shops · ${zeroCount} with zero sales`\n        : `${rows.length} of ${totalUniverse} shops (filtered) · ${zeroCount} with zero sales`;\n\n    const tbody = $(\'lbBody\');\n    tbody.innerHTML = \'\';\n    rows.forEach((r,i)=>{\n      const tr = document.createElement(\'tr\');\n      const isZero = r.qty===0;\n      if(isZero) tr.className = \'zero-row\';\n      const badgeClass = (!isZero && i===0)?\'r1\':(!isZero && i===1)?\'r2\':(!isZero && i===2)?\'r3\':\'\';\n      tr.innerHTML = `\n        <td><span class="rank-badge ${badgeClass}">${i+1}</span></td>\n        <td class="shop-name">${r.shop}</td>\n        <td>${r.region} · ${r.area.replace(/^(BMA|UPC)\\s*[IVX]*\\s*-\\s*/,\'\')}</td>\n        <td class="num">${fmtInt(r.qty)}</td>\n        <td class="num bar-cell">${isZero ? \'—\' : \'฿\'+fmtInt(r.rev)}\n          <span class="track" style="width:calc(100% - 20px)"></span>\n          <span class="fill" style="width:${isZero ? 0 : (r.rev/maxRev*90).toFixed(1)}%"></span>\n        </td>`;\n      tbody.appendChild(tr);\n    });\n  }\n\n  pageEl.querySelectorAll(\'th[data-sort]\').forEach(th=>{\n    th.addEventListener(\'click\', ()=>{\n      const key = th.dataset.sort;\n      if(state.sortKey===key) state.sortDir = state.sortDir===\'desc\'?\'asc\':\'desc\';\n      else { state.sortKey = key; state.sortDir=\'desc\'; }\n      renderLeaderboard();\n    });\n  });\n\n  $(\'resetBtn\').addEventListener(\'click\', ()=>{\n    state.region=\'All\'; state.type=\'All\'; state.areas=new Set(); state.shop=\'All\'; state.dates=new Set(DATES);\n    shopInput.value=\'\';\n    renderAll();\n  });\n\n  function renderAll(){\n    renderRegionChips();\n    renderTypeChips();\n    renderAreaChips();\n    renderDateChips();\n    renderShopSearch();\n    renderKPIs();\n    renderTrend();\n    renderRegionChart();\n    renderBrandChart();\n    renderModelChart();\n    renderAreaList();\n    renderLeaderboard();\n  }\n\n  return { renderAll };\n}\n\n// =====================================================================\n// createTrendPage(cfg) builds the Trend Performance tab: MOM summary\n// banner, tier breakdown, overall trend chart, and a filterable /\n// scrollable shop-level trend table with sparklines + conditional\n// formatting. Built from the "MOM AMOUNT" sheet (monthly totals per shop).\n// =====================================================================\nfunction createTrendPage(payload){\n  const $ = (id) => document.getElementById(\'trend-\'+id);\n  const RECORDS = payload.records;\n  const MONTHS = payload.months; // [{key,label}, ...] ascending\n  const DATA_AS_OF = payload.dataAsOf;\n  const CURR = MONTHS[MONTHS.length-1];\n  const PREV = MONTHS[MONTHS.length-2];\n\n  const fmtInt = n => Math.round(n).toLocaleString(\'en-US\');\n  const fmtPct = n => (n>=0?\'+\':\'\') + (n*100).toFixed(1)+\'%\';\n\n  function tierOf(m){\n    if(m===null || m===undefined || isNaN(m)) return \'n/a\';\n    if(m<0) return \'Negative\';\n    if(m<0.30) return \'0-30%\';\n    if(m<0.50) return \'30-50%\';\n    if(m<1.00) return \'50-100%\';\n    return \'>100%\';\n  }\n  const TIER_ORDER = [\'Negative\',\'0-30%\',\'30-50%\',\'50-100%\',\'>100%\'];\n  const TIER_CLASS = {\'Negative\':\'tier-neg\',\'0-30%\':\'tier-low\',\'30-50%\':\'tier-mid\',\'50-100%\':\'tier-high\',\'>100%\':\'tier-vhigh\'};\n\n  RECORDS.forEach(r=>{ r.tier = tierOf(r.mom); });\n\n  const REGIONS = [...new Set(RECORDS.map(r=>r.region))].sort();\n  const AREA_TO_REGION = {};\n  RECORDS.forEach(r=>{AREA_TO_REGION[r.area]=r.region;});\n  const ALL_AREAS = REGIONS.flatMap(reg => Object.keys(AREA_TO_REGION).filter(a=>AREA_TO_REGION[a]===reg).sort());\n  const TYPES = [...new Set(RECORDS.map(r=>r.type))].sort();\n  const SHOP_NAMES = RECORDS.map(r=>r.shop).sort();\n\n  const state = { regions:new Set(), areas:new Set(), types:new Set(), shops:new Set(), tiers:new Set() };\n\n  function getFiltered(){\n    return RECORDS.filter(r=>\n      (state.regions.size===0 || state.regions.has(r.region)) &&\n      (state.areas.size===0 || state.areas.has(r.area)) &&\n      (state.types.size===0 || state.types.has(r.type)) &&\n      (state.shops.size===0 || state.shops.has(r.shop)) &&\n      (state.tiers.size===0 || state.tiers.has(r.tier))\n    );\n  }\n\n  // ---------- Summary banner ----------\n  function renderBanner(){\n    const filtered = getFiltered();\n    $(\'dataOf\').textContent = \'Data as of \' + DATA_AS_OF;\n    $(\'prevLabel\').textContent = PREV.label;\n    $(\'currLabel\').textContent = CURR.label;\n    const prevTotal = filtered.reduce((s,r)=>s+(r.months[PREV.key]||0),0);\n    const currTotal = filtered.reduce((s,r)=>s+(r.months[CURR.key]||0),0);\n    const overallMom = prevTotal ? (currTotal-prevTotal)/prevTotal : 0;\n    $(\'prevTotal\').textContent = fmtInt(prevTotal);\n    $(\'currTotal\').textContent = fmtInt(currTotal);\n    $(\'overallMom\').textContent = filtered.length ? fmtPct(overallMom) : \'n/a\';\n    $(\'overallMom\').style.color = overallMom>=0 ? \'#1E8449\' : \'#C0392B\';\n\n    const counts = {};\n    TIER_ORDER.forEach(t=>counts[t]=0);\n    filtered.forEach(r=>{ if(counts[r.tier]!==undefined) counts[r.tier]++; });\n\n    const el = $(\'tierRow\');\n    el.innerHTML = \'\';\n    TIER_ORDER.forEach(t=>{\n      const div = document.createElement(\'div\');\n      div.className = \'tier-badge \'+TIER_CLASS[t];\n      div.innerHTML = `<div class="tier-count">${counts[t]}</div><div class="tier-label">${t}</div>`;\n      el.appendChild(div);\n    });\n  }\n\n  // ---------- Overall trend chart ----------\n  let overallChart;\n  function renderOverallChart(){\n    const filtered = getFiltered();\n    const totals = MONTHS.map(m => filtered.reduce((s,r)=>s+(r.months[m.key]||0),0));\n    const isFiltered = filtered.length !== RECORDS.length;\n    $(\'chartTitle\').textContent = isFiltered ? \'Trend — Filtered Selection\' : \'Overall Trend (all shops)\';\n    $(\'chartHint\').textContent = isFiltered ? `${filtered.length} of ${RECORDS.length} shops` : \'\';\n    const ctx = $(\'overallChart\');\n    if(overallChart) overallChart.destroy();\n    overallChart = new Chart(ctx, {\n      type:\'line\',\n      data:{\n        labels: MONTHS.map(m=>m.label),\n        datasets:[{\n          label: isFiltered ? `Revenue (${filtered.length} shop${filtered.length===1?\'\':\'s\'})` : \'Total Revenue (THB)\',\n          data: totals,\n          borderColor: isFiltered ? \'#E8483C\' : \'#101B3D\',\n          backgroundColor: isFiltered ? \'rgba(232,72,60,0.08)\' : \'rgba(16,27,61,0.08)\',\n          fill:true, tension:.35, pointRadius:4,\n          pointBackgroundColor: isFiltered ? \'#E8483C\' : \'#101B3D\', borderWidth:2.5\n        }]\n      },\n      options:{\n        responsive:true, maintainAspectRatio:false,\n        plugins:{legend:{display:false}, tooltip:{callbacks:{label:(c)=>\'฿\'+c.parsed.y.toLocaleString()}}},\n        scales:{\n          y:{beginAtZero:false, ticks:{callback:(v)=>(v/1e6).toFixed(1)+\'M\'}, grid:{color:\'#EEF0F6\'}},\n          x:{grid:{display:false}}\n        }\n      }\n    });\n  }\n\n  // ---------- Sparkline (tiny inline SVG, no chart library) ----------\n  function sparkline(values){\n    const w=110, h=30, pad=3;\n    const vals = values.map(v=>v===null||v===undefined?0:v);\n    const min = Math.min(...vals), max = Math.max(...vals);\n    const range = (max-min)||1;\n    const step = (w-pad*2)/(vals.length-1);\n    const pts = vals.map((v,i)=>{\n      const x = pad + i*step;\n      const y = h-pad - ((v-min)/range)*(h-pad*2);\n      return x.toFixed(1)+\',\'+y.toFixed(1);\n    }).join(\' \');\n    const lastUp = vals[vals.length-1] >= vals[vals.length-2];\n    const color = lastUp ? \'#1E8449\' : \'#C0392B\';\n    return `<svg class="spark-svg" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">\n      <polyline points="${pts}" fill="none" stroke="${color}" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round"/>\n    </svg>`;\n  }\n\n  // ---------- MOM % conditional color (red -> yellow -> green) ----------\n  function momColor(m){\n    if(m===null||m===undefined||isNaN(m)) return {bg:\'#F0F1F6\', fg:\'#8890A0\'};\n    const clamped = Math.max(-0.5, Math.min(1.0, m));\n    let hue;\n    if(clamped<=0) hue = 0 + (clamped+0.5)/0.5*60;      // -50%→0(red) ... 0%→60(yellow)\n    else hue = 60 + Math.min(clamped,1.0)/1.0*60;        // 0%→60(yellow) ... 100%→120(green)\n    return {bg:`hsl(${hue.toFixed(0)},72%,88%)`, fg:`hsl(${hue.toFixed(0)},60%,28%)`};\n  }\n\n  // ---------- Multi-select dropdowns (checkbox panel, cross-filtering / faceted) ----------\n  // A record "passes" a facet check for all filters EXCEPT the one named\n  // `exclude` -- this is what makes each dropdown\'s option list reflect\n  // every OTHER currently active filter (e.g. picking an Area narrows the\n  // Shop Name list to shops actually in that area).\n  function passesFacet(r, exclude){\n    return (exclude===\'region\' || state.regions.size===0 || state.regions.has(r.region)) &&\n           (exclude===\'area\'   || state.areas.size===0   || state.areas.has(r.area))     &&\n           (exclude===\'type\'   || state.types.size===0   || state.types.has(r.type))     &&\n           (exclude===\'shop\'   || state.shops.size===0   || state.shops.has(r.shop))     &&\n           (exclude===\'tier\'   || state.tiers.size===0   || state.tiers.has(r.tier));\n  }\n  function facetOptions(field, exclude, orderedUniverse){\n    return orderedUniverse.filter(v => RECORDS.some(r => r[field]===v && passesFacet(r, exclude)));\n  }\n  // After ANY filter change, drop selections that are no longer reachable\n  // given the other active filters (avoids invisible "orphan" selections).\n  // IMPORTANT: mutate each Set in place (delete/add) -- never reassign\n  // state.xxx to a new Set, since the dropdown widgets hold a direct\n  // reference to the original Set object.\n  function pruneSetInPlace(set, field, universe){\n    const valid = new Set(facetOptions(field, field, universe));\n    [...set].forEach(v=>{ if(!valid.has(v)) set.delete(v); });\n  }\n  function pruneAllFacets(){\n    pruneSetInPlace(state.regions, \'region\', REGIONS);\n    pruneSetInPlace(state.areas,   \'area\',   ALL_AREAS);\n    pruneSetInPlace(state.types,   \'type\',   TYPES);\n    pruneSetInPlace(state.shops,   \'shop\',   SHOP_NAMES);\n    pruneSetInPlace(state.tiers,   \'tier\',   TIER_ORDER);\n  }\n\n  function closeAllPanels(){\n    document.querySelectorAll(\'.msdd-panel.open\').forEach(p=>p.classList.remove(\'open\'));\n  }\n  document.addEventListener(\'click\', closeAllPanels);\n\n  function buildMultiSelect(name, getOptions, selectedSet, opts){\n    opts = opts || {};\n    const btn = $(name+\'-btn\');\n    const panel = $(name+\'-panel\');\n    const withSearch = !!opts.search;\n\n    function label(){\n      if(selectedSet.size===0) return \'All ▾\';\n      if(selectedSet.size===1) return [...selectedSet][0]+\' ▾\';\n      return selectedSet.size+\' selected ▾\';\n    }\n\n    function renderPanel(filterText){\n      panel.innerHTML = \'\';\n      const actions = document.createElement(\'div\');\n      actions.className = \'msdd-actions\';\n      const optionsList = getOptions();\n      const allLink = document.createElement(\'a\');\n      allLink.textContent = \'Select all\';\n      allLink.onclick = ()=>{ optionsList.forEach(o=>selectedSet.add(o)); if(opts.onChange) opts.onChange(); refresh(); };\n      const clearLink = document.createElement(\'a\');\n      clearLink.textContent = \'Clear\';\n      clearLink.onclick = ()=>{ selectedSet.clear(); if(opts.onChange) opts.onChange(); refresh(); };\n      actions.appendChild(allLink);\n      actions.appendChild(clearLink);\n      panel.appendChild(actions);\n\n      if(withSearch){\n        const search = document.createElement(\'input\');\n        search.className = \'msdd-search\';\n        search.placeholder = \'Search…\';\n        search.value = filterText || \'\';\n        search.addEventListener(\'click\', e=>e.stopPropagation());\n        search.addEventListener(\'input\', ()=> renderPanel(search.value));\n        panel.appendChild(search);\n        setTimeout(()=>{ search.focus(); search.selectionStart = search.selectionEnd = search.value.length; },0);\n      }\n\n      const visible = filterText\n        ? optionsList.filter(o=>o.toLowerCase().includes(filterText.toLowerCase()))\n        : optionsList;\n\n      if(optionsList.length===0){\n        const empty = document.createElement(\'div\');\n        empty.className = \'msdd-empty\';\n        empty.textContent = \'No options with current filters\';\n        panel.appendChild(empty);\n      } else if(visible.length===0){\n        const empty = document.createElement(\'div\');\n        empty.className = \'msdd-empty\';\n        empty.textContent = \'No matches\';\n        panel.appendChild(empty);\n      }\n      visible.forEach(opt=>{\n        const item = document.createElement(\'label\');\n        item.className = \'msdd-item\';\n        const cb = document.createElement(\'input\');\n        cb.type = \'checkbox\';\n        cb.checked = selectedSet.has(opt);\n        cb.addEventListener(\'click\', e=>e.stopPropagation());\n        cb.addEventListener(\'change\', ()=>{\n          if(cb.checked) selectedSet.add(opt); else selectedSet.delete(opt);\n          refreshButton();\n          if(opts.onChange) setTimeout(()=>opts.onChange(), 0);\n        });\n        item.appendChild(cb);\n        item.appendChild(document.createTextNode(opt));\n        panel.appendChild(item);\n      });\n    }\n\n    function refreshButton(){\n      btn.textContent = label();\n      btn.classList.toggle(\'has-selection\', selectedSet.size>0);\n    }\n\n    function refresh(){\n      refreshButton();\n      if(panel.classList.contains(\'open\')){\n        const existingSearch = panel.querySelector(\'.msdd-search\');\n        renderPanel(existingSearch ? existingSearch.value : undefined);\n      }\n    }\n\n    btn.addEventListener(\'click\', e=>{\n      e.stopPropagation();\n      const willOpen = !panel.classList.contains(\'open\');\n      closeAllPanels();\n      if(willOpen){ renderPanel(); panel.classList.add(\'open\'); }\n    });\n    panel.addEventListener(\'click\', e=>e.stopPropagation());\n\n    refreshButton();\n    return { refresh };\n  }\n\n  function onAnyFacetChange(){ pruneAllFacets(); renderAll(); }\n\n  const ddRegion = buildMultiSelect(\'fRegion\', ()=>facetOptions(\'region\',\'region\', REGIONS), state.regions, { onChange: onAnyFacetChange });\n  const ddArea   = buildMultiSelect(\'fArea\',   ()=>facetOptions(\'area\',\'area\', ALL_AREAS),   state.areas,   { search:true, onChange: onAnyFacetChange });\n  const ddType   = buildMultiSelect(\'fType\',   ()=>facetOptions(\'type\',\'type\', TYPES),       state.types,   { onChange: onAnyFacetChange });\n  const ddShop   = buildMultiSelect(\'fShop\',   ()=>facetOptions(\'shop\',\'shop\', SHOP_NAMES),  state.shops,   { search:true, onChange: onAnyFacetChange });\n  const ddTier   = buildMultiSelect(\'fTier\',   ()=>facetOptions(\'tier\',\'tier\', TIER_ORDER),  state.tiers,   { onChange: onAnyFacetChange });\n\n  function renderFilters(){\n    ddRegion.refresh();\n    ddArea.refresh();\n    ddType.refresh();\n    ddShop.refresh();\n    ddTier.refresh();\n  }\n\n  $(\'resetBtn\').addEventListener(\'click\', ()=>{\n    state.regions.clear(); state.areas.clear(); state.types.clear(); state.shops.clear(); state.tiers.clear();\n    renderAll();\n  });\n\n  // ---------- Export CSV (respects current filters + sort) ----------\n  function csvField(v){\n    const s = (v===null || v===undefined) ? \'\' : String(v);\n    return /[",\\n]/.test(s) ? \'"\'+s.replace(/"/g,\'""\')+\'"\' : s;\n  }\n  function exportCsv(){\n    const rows = getFiltered().slice().sort((a,b)=> (b.mom??-99) - (a.mom??-99));\n    const header = [\'Shop Name\',\'Region\',\'Area\',\'Type\', ...MONTHS.map(m=>m.label), \'MOM %\'];\n    const lines = [header.map(csvField).join(\',\')];\n    rows.forEach(r=>{\n      const cells = [\n        r.shop, r.region, r.area, r.type,\n        ...MONTHS.map(m => r.months[m.key]==null ? \'\' : r.months[m.key]),\n        r.mom==null ? \'\' : (r.mom*100).toFixed(1)+\'%\'\n      ];\n      lines.push(cells.map(csvField).join(\',\'));\n    });\n    const csv = \'\\uFEFF\' + lines.join(\'\\r\\n\'); // BOM for Excel UTF-8 (Thai text) compatibility\n    const blob = new Blob([csv], {type:\'text/csv;charset=utf-8;\'});\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement(\'a\');\n    const stamp = new Date().toISOString().slice(0,10);\n    const scopeTag = [\n      ...state.regions, ...state.areas, ...state.types, ...state.tiers\n    ].join(\'_\').replace(/[^a-zA-Z0-9_-]/g,\'\').slice(0,60);\n    a.href = url;\n    a.download = `Trend_Performance${scopeTag?\'_\'+scopeTag:\'\'}_${stamp}.csv`;\n    document.body.appendChild(a);\n    a.click();\n    document.body.removeChild(a);\n    URL.revokeObjectURL(url);\n  }\n  $(\'exportBtn\').addEventListener(\'click\', exportCsv);\n\n  // ---------- Table (header built once; body re-rendered on filter change) ----------\n  function renderHead(){\n    const tr = $(\'headRow\');\n    tr.innerHTML = \'\';\n    const cols = [\'Shop Name\',\'Region\',\'Area\',\'Type\', ...MONTHS.map(m=>m.label), \'MOM %\', \'Trend (Jan–\' + CURR.label.split(\' \')[0] + \')\'];\n    cols.forEach((c,i)=>{\n      const th = document.createElement(\'th\');\n      th.textContent = c;\n      if(i===0) th.className = \'col-shop\';\n      tr.appendChild(th);\n    });\n  }\n\n  function renderBody(){\n    const rows = getFiltered().slice().sort((a,b)=> (b.mom??-99) - (a.mom??-99));\n    $(\'tableHint\').textContent = rows.length + \' of \' + RECORDS.length + \' shops\';\n    const tbody = $(\'tbody\');\n    tbody.innerHTML = \'\';\n    rows.forEach(r=>{\n      const tr = document.createElement(\'tr\');\n      let html = `<td class="col-shop">${r.shop}</td>`;\n      html += `<td class="col-meta">${r.region}</td>`;\n      html += `<td class="col-meta">${r.area.replace(/^(BMA|UPC)\\s*[IVX]*\\s*-\\s*/,\'\')}</td>`;\n      html += `<td class="col-meta">${r.type}</td>`;\n      MONTHS.forEach(m=>{\n        const v = r.months[m.key];\n        const isHighlight = (m.key===PREV.key || m.key===CURR.key);\n        html += `<td class="${isHighlight?\'col-highlight\':\'\'}">${v==null?\'—\':fmtInt(v)}</td>`;\n      });\n      const c = momColor(r.mom);\n      html += `<td class="col-mom" style="background:${c.bg};color:${c.fg}">${r.mom==null?\'n/a\':fmtPct(r.mom)}</td>`;\n      html += `<td class="col-trend">${sparkline(MONTHS.map(m=>r.months[m.key]))}</td>`;\n      tr.innerHTML = html;\n      tbody.appendChild(tr);\n    });\n  }\n\n  function renderAll(){\n    renderBanner();\n    renderOverallChart();\n    renderFilters();\n    renderHead();\n    renderBody();\n  }\n\n  return { renderAll };\n}\n\n// =====================================================================\n// Instantiate pages. Handset renders immediately (visible on load).\n// Accessories is lazily rendered the first time its tab is opened, so\n// its charts are created while their canvases are actually visible\n// (avoids zero-size canvas issues with display:none).\n// =====================================================================\nconst handsetDashboard = createDashboard({\n  prefix: \'handset\',\n  data: HANDSET_DATA,\n  shopsMaster: SHOPS_MASTER,\n  unitLabel: \'unit\'\n});\nhandsetDashboard.renderAll();\n\nlet accessoriesDashboard = null;\nlet trendPage = null;\n\ndocument.querySelectorAll(\'.tab-btn\').forEach(btn=>{\n  btn.addEventListener(\'click\', ()=>{\n    const page = btn.dataset.page;\n    document.querySelectorAll(\'.tab-btn\').forEach(b=>b.classList.remove(\'active\'));\n    btn.classList.add(\'active\');\n    document.querySelectorAll(\'.page\').forEach(p=>p.classList.remove(\'active\'));\n    document.getElementById(\'page-\'+page).classList.add(\'active\');\n\n    if(page===\'accessories\' && !accessoriesDashboard){\n      accessoriesDashboard = createDashboard({\n        prefix: \'accessories\',\n        data: ACCESSORIES_DATA,\n        shopsMaster: SHOPS_MASTER,\n        unitLabel: \'unit\'\n      });\n      accessoriesDashboard.renderAll();\n    }\n    if(page===\'trend\' && !trendPage){\n      trendPage = createTrendPage(MOM_PAYLOAD);\n      trendPage.renderAll();\n    }\n  });\n});\n'
